def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 30 + np.log1p(cap) * 40 + np.exp(-usage)
        fluctuation = 0.0
        factor = np.sin(cap * 2.3) + np.cos(usage * 7.5)
        adjustment = 0.0
        if usage > 5:
            base_priority += 7000 * (usage ** 1.15)
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 50 * np.cos(cap * 1.8)
            else:
                base_priority -= 60 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 25 / i
            if int(cap * 500) % 7 == 0:
                adjustment += 80 * np.tanh(cap / 20)
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2000 * delta ** 2 + 250 * (1 - np.sqrt(delta))
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.4)) * 30 / j
            if int(cap * 2.5) % 4 == 1:
                adjustment += 55 * np.sin(cap / 12)
        elif 3 < usage <=4:
            base_priority += 1500 * (usage - 3) ** 1.9
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 1)
                    if k == 11 and usage > 3.5:
                        fluctuation += 25
            if cap % 3.1 < 0.7:
                adjustment += 45 * np.cos(cap * 2.5)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2.3) ** 2.2
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.55:
                    fluctuation += pwr * 22 / m
                    if m % 6 == 3:
                        fluctuation += 6 * m
                else:
                    fluctuation += (1 - pwr) * 14 / (m + 3)
                    if m == 14 and usage > 2.7:
                        fluctuation += 18
            if cap % 2.7 < 0.4:
                adjustment += 38 * np.sin(cap * 3.2)
        elif 1 < usage <= 2:
            base_priority += 850 * (usage - 1.2) ** 3.3
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.65:
                    fluctuation += pwr * 30 / n
                    if n % 5 == 2:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 18 / (n + 2)
                    if n == 15 and usage > 1.9:
                        fluctuation += 22
            if cap % 1.8 < 0.25:
                adjustment += 32 * np.cos(cap * 2.2)
        elif 0.6 < usage <= 1:
            base_priority += 140 * (1 - usage) * (1+0.5*np.sin(cap*3))
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.4) * 15 / o
                if usage < 0.08 * o:
                    fluctuation -= 9 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 300
            elif cap < 1:
                base_priority += np.log1p(cap * 30) * 40
            else:
                base_priority += (cap % 7) * 18
        else:
            base_priority += 300 * (1 - usage) ** 2.5
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.35) * 16 / p
                if usage < 0.02 * p:
                    fluctuation -= 14 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1:
                base_priority += np.log1p(cap * 35) * 50
            else:
                base_priority += (cap % 8) * 28
        priority = base_priority + fluctuation + adjustment + factor * 12
        if cap < 0.05:
            priority += 85
            if usage > 0.8:
                priority += 95
            elif usage < 0.15:
                priority -= 55
                for q in range(1, 8):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 1.2:
            priority += 45
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for r in range(1, 7):
                if int(cap * 1300) % (r + 5) == 0:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.15:
                priority -= 45
                for s in range(1, 8):
                    priority -= s * 6
            elif usage > 0.95:
                priority += 95
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 35
        extra = 0
        if int(cap * 3000) % 21 == 0:
            extra += 20
        if int(cap * 1000) % 29 == 0:
            extra -= 15
        if int(cap * 200) % 11 == 0:
            extra += 18
        for u in range(1, 10):
            diff = abs(usage - u / 10)
            if diff < 0.015:
                extra += 25 / u
            elif diff < 0.04:
                extra += 13 / u
            else:
                extra -= 5 / u
        for v in range(1, 9):
            mod_chk = int(cap * 1700) % (v + 11)
            if mod_chk == 0:
                extra += v * 6
            elif mod_chk == 4:
                extra -= v * 5
        for w in range(1, 6):
            mod_chk = int(usage * 1700) % (w + 7)
            if mod_chk == 0:
                extra += 12 * w
            elif mod_chk == 4:
                extra -= 9 * w
        priority += extra
        if usage < 0.004:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.97:
            for y in range(1, 8):
                priority += y * 13
        if cap > 3.0:
            if cap % 1.2 < 0.07:
                priority += 50
            if (int(cap * 2800) % 29 == 0) and (usage > 0.75):
                priority += 70
            for z in range(1, 7):
                if (int(cap * 700) % (z + 11) == 3) and (usage < 0.88):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 5e4
        if abs(priority) > 5e4:
            priority = np.sign(priority) * 5e4
        priorities[idx] = priority
    return priorities
